// ── CH1 STATE ──
let activeCh1Lesson = 0;
let activeCh12Part = 0; // 0=Basic, 1=Conceptual, 2=Thinking

// Split lesson questions into 3 parts: last 10 = Thinking, rest split Basic/Conceptual
function getCh12Parts(lessonIdx) {
  const all = CH1_LESSONS[lessonIdx];
  const thinking = all.slice(-10);
  const remaining = all.slice(0, all.length - 10);
  const half = Math.floor(remaining.length / 2);
  const basic = remaining.slice(0, half);
  const conceptual = remaining.slice(half);
  return [basic, conceptual, thinking];
}

// ── CH1 LESSON NAVIGATION ──
function startCh1Lesson(lessonIdx) {
  activeCh1Lesson = lessonIdx;
  startCh12Part(0); // always start from Basic
}

function startCh12Part(partIdx, forceReset) {
  activeCh12Part = partIdx;
  const meta = CH1_LESSON_META[activeCh1Lesson];
  const parts = getCh12Parts(activeCh1Lesson);
  const partLabels = ["Basic","Conceptual","Thinking-Based"];

  window._ch1Mode = true;
  window._ch1Meta = {
    label: "Lesson " + (activeCh1Lesson + 1) + " · " + partLabels[partIdx],
    title: meta.title,
    color: meta.color
  };
  window._fromCh1 = true;
  currentPart = 0;
  questions = parts[partIdx];
  current = 0;
  answers = new Array(questions.length).fill(null);
  score = 0;
  totalAnswered = 0;

  // Restore saved progress if logged in (unless forced reset from retry)
  if (!forceReset) {
    const progressKey = 'ch1_' + activeCh1Lesson + '_' + partIdx;
    const saved = loadProgress(progressKey);
    if (saved && saved.answers && saved.answers.length === questions.length) {
      answers = saved.answers;
      current = saved.current || 0;
      score = saved.score || 0;
      totalAnswered = saved.totalAnswered || 0;
    }
  }

  document.getElementById("homePage").style.display = "none";
  document.getElementById("chapterPage").style.display = "none";
  document.getElementById("ch1Page").style.display = "none";
  document.getElementById("landingPage").style.display = "none";
  document.getElementById("resultsPage").style.display = "none";
  document.getElementById("quizPage").style.display = "flex";

  // Show ch12 badges, hide book1 badges
  document.getElementById("partBadgesWrap").style.display = "none";
  document.getElementById("ch12BadgesWrap").style.display = "flex";

  // Set active badge
  ["ch12b0","ch12b1","ch12b2"].forEach((id, i) => {
    const el = document.getElementById(id);
    if (el) el.classList.toggle("active", i === partIdx);
  });

  // Update badge counts dynamically
  const allParts = getCh12Parts(activeCh1Lesson);
  const b0 = document.getElementById("ch12b0");
  const b1 = document.getElementById("ch12b1");
  const b2 = document.getElementById("ch12b2");
  if (b0) b0.textContent = "● Basic Q1–" + allParts[0].length;
  if (b1) b1.textContent = "● Conceptual Q" + (allParts[0].length+1) + "–" + (allParts[0].length+allParts[1].length);
  if (b2) b2.textContent = "● Thinking Q" + (allParts[0].length+allParts[1].length+1) + "–" + (allParts[0].length+allParts[1].length+allParts[2].length);

  buildDots();
  renderQ();
}

