// ── LOGIN SYSTEM ──
let currentUser = null;

// Simple localStorage based auth (frontend only)
function getUsers() {
  try { return JSON.parse(localStorage.getItem('qm_users') || '{}'); } catch(e) { return {}; }
}
function saveUsers(u) { localStorage.setItem('qm_users', JSON.stringify(u)); }
function saveSession(user) {
  localStorage.setItem('qm_session', JSON.stringify(user));
  currentUser = user;
}
function clearSession() {
  localStorage.removeItem('qm_session');
  currentUser = null;
}
function loadSession() {
  try {
    const s = localStorage.getItem('qm_session');
    if (s) { currentUser = JSON.parse(s); updateLoginBtn(); }
  } catch(e) {}
}

function updateLoginBtn() {
  const container = document.getElementById('authButtons');
  if (!container) return;
  if (currentUser) {
    const initial = currentUser.name ? currentUser.name.charAt(0).toUpperCase() : currentUser.email.charAt(0).toUpperCase();
    container.innerHTML = `<div class="user-circle" onclick="showUserMenu()" title="${currentUser.name || currentUser.email}">${initial}</div>`;
  } else {
    container.innerHTML = `<button class="btn-auth-login" onclick="openLoginModal()">Log in</button><button class="btn-auth-signup" onclick="openLoginModal(); switchTab('signup')">Sign up for free</button>`;
  }
}

function openLoginModal() {
  const modal = document.getElementById('loginModal');
  modal.classList.add('open');
  // Reset to step 1
  document.getElementById('authStep1').style.display = 'block';
  document.getElementById('authStep2').style.display = 'none';
  document.getElementById('authStep3').style.display = 'none';
  document.getElementById('authEmail').value = '';
  document.getElementById('authMsg1').textContent = '';
  if (document.getElementById('loginPass')) document.getElementById('loginPass').value = '';
  if (document.getElementById('signupName')) document.getElementById('signupName').value = '';
  if (document.getElementById('signupPass')) document.getElementById('signupPass').value = '';
}
function closeLoginModal() {
  document.getElementById('loginModal').classList.remove('open');
}
function closeLoginModalOutside(e) {
  if (e.target === document.getElementById('loginModal')) closeLoginModal();
}

// Keep for compatibility
function switchTab(tab) {
  if (tab === 'signup') openLoginModal();
}

// Step flow: email → check if user exists → login or signup
function goToStep2() {
  const email = document.getElementById('authEmail').value.trim();
  const msg = document.getElementById('authMsg1');
  if (!email || !email.includes('@')) {
    msg.className = 'modal-msg err';
    msg.textContent = 'Please enter a valid email address.';
    return;
  }
  msg.textContent = '';
  const users = getUsers();
  if (users[email]) {
    // Existing user → login step
    document.getElementById('authStep1').style.display = 'none';
    document.getElementById('authStep2').style.display = 'block';
    document.getElementById('step2Email').textContent = email;
    document.getElementById('loginPass').value = '';
    document.getElementById('loginMsg').textContent = '';
  } else {
    // New user → signup step
    document.getElementById('authStep1').style.display = 'none';
    document.getElementById('authStep3').style.display = 'block';
    document.getElementById('step3Email').textContent = email;
    document.getElementById('signupName').value = '';
    document.getElementById('signupPass').value = '';
    document.getElementById('signupMsg').textContent = '';
  }
}

function backToStep1() {
  document.getElementById('authStep1').style.display = 'block';
  document.getElementById('authStep2').style.display = 'none';
  document.getElementById('authStep3').style.display = 'none';
}

// SHA-256 password hashing utility
async function hashPassword(password) {
  const encoder = new TextEncoder();
  const data = encoder.encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

// Migrate old base64 passwords to SHA-256 on login
async function migratePassword(users, email, plainPass) {
  const hashed = await hashPassword(plainPass);
  users[email].pass = hashed;
  saveUsers(users);
  return hashed;
}

async function doLogin() {
  const email = document.getElementById('step2Email').textContent.trim();
  const pass = document.getElementById('loginPass').value;
  const msg = document.getElementById('loginMsg');
  if (!pass) { msg.className='modal-msg err'; msg.textContent='Password zaruri hai.'; return; }
  const users = getUsers();
  const user = users[email];
  if (!user) { msg.className='modal-msg err'; msg.textContent='Account nahi mila.'; return; }
  const hashed = await hashPassword(pass);
  // Support migrating old base64 passwords
  if (user.pass === btoa(pass)) {
    await migratePassword(users, email, pass);
  } else if (user.pass !== hashed) {
    msg.className='modal-msg err'; msg.textContent='Password galat hai.'; return;
  }
  msg.className='modal-msg ok'; msg.textContent='✅ Login successful!';
  saveSession({email, name: user.name});
  updateLoginBtn();
  refreshProgressBadges();
  setTimeout(closeLoginModal, 800);
}

async function doSignup() {
  const email = document.getElementById('step3Email').textContent.trim();
  const name = document.getElementById('signupName').value.trim();
  const pass = document.getElementById('signupPass').value;
  const msg = document.getElementById('signupMsg');
  if (!name || !pass) { msg.className='modal-msg err'; msg.textContent='Sab fields fill karo.'; return; }
  if (pass.length < 6) { msg.className='modal-msg err'; msg.textContent='Password kam az kam 6 characters ka ho.'; return; }
  const users = getUsers();
  if (users[email]) { msg.className='modal-msg err'; msg.textContent='Yeh email already registered hai.'; return; }
  const hashed = await hashPassword(pass);
  users[email] = {name, pass: hashed};
  saveUsers(users);
  msg.className='modal-msg ok'; msg.textContent='✅ Account bana gaya! Logging in...';
  saveSession({email, name});
  updateLoginBtn();
  refreshProgressBadges();
  setTimeout(closeLoginModal, 800);
}

function showUserMenu() {
  if (!currentUser) return;
  const confirmLogout = confirm(`Logged in as: ${currentUser.name || currentUser.email}\n\nLogout karna chahte hain?`);
  if (confirmLogout) {
    clearSession();
    updateLoginBtn();
    refreshProgressBadges();
  }
}

// Keyboard ESC to close modal
document.addEventListener('keydown', e => { if (e.key === 'Escape') closeLoginModal(); });

// ── PROGRESS BADGES ──
function refreshProgressBadges() {
  if (!currentUser) {
    // Hide all progress badges when not logged in
    document.querySelectorAll('.pc-progress').forEach(el => {
      el.className = 'pc-progress';
      el.innerHTML = '';
    });
    return;
  }
  const store = getUserProgressStore() || {};

  // 300Q parts
  for (let i = 0; i < 3; i++) {
    const el = document.getElementById('prog300q' + i);
    if (!el) continue;
    const saved = store['300q_' + i];
    if (saved && saved.answers) {
      const done = saved.answers.filter(a => a !== null).length;
      const total = saved.answers.length;
      const correct = saved.answers.filter((a, j) => {
        if (a === null || a === -1) return false;
        const qs = getPartQuestions(i);
        return a === qs[j].ans;
      }).length;
      const pct = Math.round((done / total) * 100);
      const isComplete = done === total;
      const fillColor = isComplete ? 'var(--green)' : 'var(--gold)';
      el.className = 'pc-progress has-progress' + (isComplete ? ' complete' : '');
      if (isComplete) {
        el.innerHTML = `<span>✅ ${correct}/${total} correct</span>`;
      } else {
        el.innerHTML = `<span>${done}/${total}</span><div class="prog-bar-bg"><div class="prog-bar-fill" style="width:${pct}%;background:${fillColor}"></div></div><span>${pct}%</span>`;
      }
    } else {
      el.className = 'pc-progress';
      el.innerHTML = '';
    }
  }

  // Ch12 lesson cards — show combined progress across all 3 sub-parts
  for (let l = 0; l < 10; l++) {
    const el = document.getElementById('progCh1L' + l);
    if (!el) continue;
    let totalDone = 0, totalQs = 0, totalCorrect = 0;
    const parts = getCh12Parts(l);
    for (let p = 0; p < 3; p++) {
      const saved = store['ch1_' + l + '_' + p];
      totalQs += parts[p].length;
      if (saved && saved.answers) {
        totalDone += saved.answers.filter(a => a !== null).length;
        totalCorrect += saved.answers.filter((a, j) => {
          if (a === null || a === -1) return false;
          return a === parts[p][j].ans;
        }).length;
      }
    }
    if (totalDone > 0) {
      const pct = Math.round((totalDone / totalQs) * 100);
      const isComplete = totalDone === totalQs;
      const fillColor = isComplete ? 'var(--green)' : 'var(--gold)';
      el.className = 'pc-progress has-progress' + (isComplete ? ' complete' : '');
      if (isComplete) {
        el.innerHTML = `<span>✅ ${totalCorrect}/${totalQs} correct</span>`;
      } else {
        el.innerHTML = `<span>${totalDone}/${totalQs}</span><div class="prog-bar-bg"><div class="prog-bar-fill" style="width:${pct}%;background:${fillColor}"></div></div><span>${pct}%</span>`;
      }
    } else {
      el.className = 'pc-progress';
      el.innerHTML = '';
    }
  }
}

// Load session on page load
loadSession();
refreshProgressBadges();
